<?php
namespace Database\Seeders; use Illuminate\Database\Seeder; use Spatie\Permission\Models\{Permission,Role}; use Spatie\Permission\PermissionRegistrar;
class InventoryPermissionSeeder extends Seeder{public function run():void{$all=['inventory.view','inventory.create','inventory.update','inventory.delete','inventory.manage-master','inventory.adjust','inventory.transfer','inventory.change-condition','inventory.stock-opname','inventory.verify','inventory.reverse','inventory.report','inventory.print','inventory.export']; foreach($all as $p) Permission::firstOrCreate(['name'=>$p,'guard_name'=>'web']); foreach(['super-admin','admin-madrasah'] as $r) Role::findByName($r)->givePermissionTo($all); Role::findByName('kepala-madrasah')->givePermissionTo(['inventory.view','inventory.report','inventory.print','inventory.export','inventory.verify']); Role::findByName('tata-usaha')->givePermissionTo(['inventory.view','inventory.create','inventory.update','inventory.manage-master','inventory.adjust','inventory.transfer','inventory.change-condition','inventory.stock-opname','inventory.report','inventory.print','inventory.export']); Role::findByName('operator')->givePermissionTo(['inventory.view','inventory.create','inventory.update','inventory.manage-master','inventory.adjust','inventory.transfer','inventory.change-condition','inventory.stock-opname','inventory.report']); Role::findByName('bendahara')->givePermissionTo(['inventory.view','inventory.report','inventory.print','inventory.export']); app(PermissionRegistrar::class)->forgetCachedPermissions();}}
